import Page from 'components/Page';
import React from 'react';
import Searchable from 'react-select';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import { checkInBook, findBooks } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
class LibraryBookRtnPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          book : 'nn',
        //   user : '',
        //   lent_from : '',
        //   lent_until : '',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          books: [],
          selectableBooks:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findBooks(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    books:response.data,
                });
                this.searchableBooksList(response.data);
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    searchableBooksList = (input) => {
        let bookOpts = [];
        
        input.forEach( function(x){
          let lbl = x.number;
          let entry = { value: x.id, label: lbl };
          bookOpts.push(entry);
        });
        this.setState({
          ...this.state,
          selectableBooks:bookOpts,
        });
      }
    handleBookInput = selectedPar => {
        const v = selectedPar.value.toString();
        this.setState({
            ...this.state, 
            book: v,
        });
    }
    // handleUserInput = (event) => {
    //     const v = event.target.value;
    //     this.setState({
    //       ...this.state, 
    //       user: v,
    //   });
    // }
    // handleLentFromInput = (event) => {
    //     const v = event.target.value;
    //     this.setState({...this.state, lent_from: v,});
    // }
    // handleLentUntilInput = (event) => {
    //     const v = event.target.value;
    //     this.setState({...this.state, lent_until: v,});
    // }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        checkInBook(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
      return (
        <Page title="Library - Book Check In" breadcrumbs={[{ name: 'Book Check In', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>{this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={5} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleEmail">Search Book*</Label>
                      <Searchable defaultValue={this.state.book} onChange={this.handleBookInput} options={this.state.selectableBooks}/>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                      <FormGroup check row>
                        <Col sm={{ size: 10, offset: 2 }}>
                            <Button type="button" onClick={this.handleSaveChanges}>Check In</Button>
                        </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>
        </Page>
      );
    }
}
export default LibraryBookRtnPage;
